#include <bits/stdc++.h>
using namespace std;
string x,y;
int a[10000],b[10000],c[10000];
int main(){
	cin>>x>>y;
	int lx=x.size(),ly=y.size();
	int len=max(lx,ly);
	for(int i=0;i<lx;i++){
		a[i]=x[lx-1-i]-'0';
	}
	for(int i=0;i<ly;i++){
		b[i]=y[ly-1-i]-'0';
	}
	for(int i=0;i<len;i++){
		c[i]+=a[i]+b[i];
		if(c[i]>=10){
			c[i+1]++;
			c[i]%=10;
		}
	}
	if(c[len]){
		len++;
	}
	for(int i=len-1;i>=0;i--){
		cout<<c[i];
	}
	return 0;
}
